 1	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 2	import { K8sCommonKebabMenu } from '../utils/k8s-common-kebab-menu';
 3	import * as React from 'react';
 4	import { RepositoryModel } from '../../models';
 5	import {
 6	  Dropdown,
 7	  DropdownList,
 8	  MenuToggle,
 9	  MenuToggleElement,
10	} from '@patternfly/react-core';
11	import EllipsisVIcon from '@patternfly/react-icons/dist/esm/icons/ellipsis-v-icon';
12	import { KEBAB_BUTTON_ID } from '../../consts';
13	
14	type RepositoriesKebabProps = {
15	  obj: K8sResourceCommon;
16	};
17	
18	const RepositoriesKebab: React.FC<RepositoriesKebabProps> = ({ obj }) => {
19	  const [isOpen, setIsOpen] = React.useState(false);
20	
21	  const onToggle = () => {
22	    setIsOpen(!isOpen);
23	  };
24	
25	  const onSelect = () => {
26	    setIsOpen(false);
27	  };
28	
29	  const dropdownItems = K8sCommonKebabMenu(obj, RepositoryModel);
30	
31	  return (
32	    <Dropdown
33	      onSelect={onSelect}
34	      onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
35	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
36	        <MenuToggle
37	          ref={toggleRef}
38	          aria-label="kebab menu"
39	          variant="plain"
40	          onClick={onToggle}
41	          isExpanded={isOpen}
42	          id={KEBAB_BUTTON_ID}
43	          data-test={KEBAB_BUTTON_ID}
44	        >
45	          <EllipsisVIcon />
46	        </MenuToggle>
47	      )}
48	      isOpen={isOpen}
49	      isPlain={false}
50	      popperProps={{ position: 'right' }}
51	    >
52	      <DropdownList>{dropdownItems}</DropdownList>
53	    </Dropdown>
54	  );
55	};
56	
57	export default RepositoriesKebab;

